import Database from 'better-sqlite3';
import path from 'node:path';
import fs from 'node:fs';
import { registry } from '../pathRegistry.js';

let db: Database.Database | null = null;

/**
 *
 */
export function getGravityDb(): Database.Database {
    if (db) return db;

    const statsDir = path.join(registry.getRoot(), '.stats');
    if (!fs.existsSync(statsDir)) {
        fs.mkdirSync(statsDir, { recursive: true });
    }

    const dbPath = path.join(statsDir, 'gravity.db');
    db = new Database(dbPath);

    db.exec(`
        CREATE TABLE IF NOT EXISTS file_gravity (
            path TEXT PRIMARY KEY,
            weight INTEGER DEFAULT 0
        );
    `);

    return db;
}

/**
 *
 */
/**
 * @param {string} filepath
 * @returns {number}
 */
export function getFileGravity(filepath: string): number {
    const database = getGravityDb();
    const normalized = registry.normalize(filepath);
    const row = database.prepare('SELECT weight FROM file_gravity WHERE path = ?').get(normalized) as { weight: number } | undefined;

    // Fallback: Also check pennyone.db if available to aggregate current session pings
    let pingWeight = 0;
    try {
        const pennyDbPath = path.join(registry.getRoot(), '.stats', 'pennyone.db');
        if (fs.existsSync(pennyDbPath)) {
            const pennyDb = new Database(pennyDbPath, { readonly: true });
            const pingRow = pennyDb.prepare('SELECT COUNT(*) as hitCount FROM pings WHERE target_path = ?').get(filepath) as { hitCount: number } | undefined;
            if (pingRow) pingWeight = pingRow.hitCount;
            pennyDb.close();
        }
    } catch { /* ignore */ }

    return (row ? row.weight : 0) + pingWeight;
}

/**
 *
 */
/**
 * Set gravity
 * @param {string} filepath - The file
 * @param {number} weight - The weight
 * @returns {void}
 */
export function updateFileGravity(filepath: string, weight: number): void {
    const database = getGravityDb();
    const normalized = registry.normalize(filepath);
    database.prepare(`
        INSERT INTO file_gravity (path, weight) 
        VALUES (?, ?) 
        ON CONFLICT(path) DO UPDATE SET weight = file_gravity.weight + ?
    `).run(normalized, weight, weight);
}

/**
 *
 */
/**
 * Set gravity
 * @param {string} filepath - The file
 * @param {number} weight - The weight
 * @returns {void}
 */
export function setFileGravity(filepath: string, weight: number): void {
    const database = getGravityDb();
    const normalized = registry.normalize(filepath);
    database.prepare(`
        INSERT INTO file_gravity (path, weight) 
        VALUES (?, ?) 
        ON CONFLICT(path) DO UPDATE SET weight = ?
    `).run(normalized, weight, weight);
}

import fs from 'node:fs/promises';
import path from 'node:path';
import chalk from 'chalk';
import { registry } from '../pathRegistry.js';

/**
 * [O.D.I.N.]: "The Gungnir Compass searches through the Hall of Records."
 */

/**
 *
 */
/**
 * Search matrix
 * @param {string} query - The query
 * @param {string} [_targetPath] - The path
 * @param _targetPath
 * @returns {Promise<any>} The results
 */
// eslint-disable-next-line @typescript-eslint/no-unused-vars
export async function searchMatrix(query: string, _targetPath: string = '.') {
    const statsDir = path.join(registry.getRoot(), '.stats');
    const graphPath = path.join(statsDir, 'matrix-graph.json');

    try {
        const raw = await fs.readFile(graphPath, 'utf-8');
        const graph = JSON.parse(raw);
        const results = [];

        const lowerQuery = query.toLowerCase();

        for (const file of graph.files) {
            const relPath = registry.getRelative(file.path);
            const intentText = file.intent || '';
            const matchesIntent = intentText.toLowerCase().includes(lowerQuery);
            const matchesPath = relPath.toLowerCase().includes(lowerQuery);
            const matchesEndpoints = file.endpoints?.some((e: string) => e.toLowerCase().includes(lowerQuery));

            if (matchesIntent || matchesPath || matchesEndpoints) {
                results.push(file);
            }
        }

        console.log(chalk.cyan(`\n ◤ GUNGNIR SEARCH: "${query}" ◢ `));
        console.log(chalk.cyan(' ' + '━'.repeat(45)));

        if (results.length === 0) {
            console.log(chalk.yellow(' [INFO] No matches found in the Hall of Records.'));
            console.log(chalk.dim(' Try a broader query or ensure a scan has been run.\n'));
            return;
        }

        results.forEach(r => {
            console.log(` ◈ ${chalk.blue(registry.getRelative(r.path))}`);
            console.log(`   ${chalk.white('Intent:')} ${chalk.italic(r.intent || '...')}`);
            if (r.endpoints?.length > 0) {
                console.log(`   ${chalk.magenta('Gateways:')} ${r.endpoints.slice(0, 2).join(', ')}`);
            }
            console.log(`   ${chalk.dim(`[L] ${r.matrix.logic.toFixed(1)} | [G] ${r.matrix.gravity}`)}`);
            console.log();
        });

        console.log(chalk.cyan(' ' + '━'.repeat(45)));
        console.log(chalk.cyan(` Found ${results.length} relevant sectors.\n`));

    } catch {
        console.error(chalk.red('[ALFRED]: "I am afraid the Hall of Records is currently inaccessible, sir."'));
    }
}

/**
 * CLI entry point for testing
 */
if (process.argv[1].includes('search')) {
    const q = process.argv.slice(2).join(' ');
    if (q) searchMatrix(q);
}

