import path from 'path';

import fs from 'fs';

/**
 * Operation PennyOne: Centralized Path Registry
 * Purpose: Eliminate path hallucination and ensure consistent normalization across the codebase.
 */
export class PathRegistry {
    private static instance: PathRegistry;
    private root: string;

    private constructor() {
        this.root = this.findProjectRoot();
    }

    /**
     * Ascend the directory tree using ESM import.meta.dirname to locate the true project root.
     * Guaranteed to only run once per instantiation (The Ascension Cache).
     */
    private findProjectRoot(): string {
        try {
            let currentDir = import.meta.dirname;
            if (process.platform === 'win32' && currentDir.startsWith('/')) {
                currentDir = currentDir.slice(1);
            }

            let previousDir = '';

            while (currentDir !== previousDir) {
                const packageJsonPath = path.join(currentDir, 'package.json');
                const agentConfigPath = path.join(currentDir, '.agent', 'config.json');

                if (fs.existsSync(packageJsonPath) || fs.existsSync(agentConfigPath)) {
                    return currentDir.replace(/\\/g, '/');
                }

                previousDir = currentDir;
                currentDir = path.dirname(currentDir);
            }
        } catch {
            // Suppress and fallback
        }

        console.warn('[WARNING] PathRegistry could not determine true project root via ascension. Falling back to process.cwd().');
        return process.cwd().replace(/\\/g, '/');
    }

    /**
     * Retrieves the cached, mathematically proven project root.
     */
    public getRoot(): string {
        return this.root;
    }

    public static getInstance(): PathRegistry {
        if (!PathRegistry.instance) {
            PathRegistry.instance = new PathRegistry();
        }
        return PathRegistry.instance;
    }

    /**
     * Standardize a path to forward-slash absolute format.
     * @param p
     */
    public normalize(p: string): string {
        if (!p) return '';
        const normalized = p.replace(/\\/g, '/');
        if (path.isAbsolute(normalized)) {
            return normalized;
        }
        return path.join(this.root, normalized).replace(/\\/g, '/');
    }

    /**
     * Resolve a relative path from a source file.
     * @param sourceFile
     * @param relativePath
     */
    public resolve(sourceFile: string, relativePath: string): string {
        const dir = path.dirname(sourceFile);
        return this.normalize(path.resolve(dir, relativePath));
    }

    /**
     * Get the relative path from the project root.
     * @param p
     */
    public getRelative(p: string): string {
        const abs = this.normalize(p);
        return path.relative(this.root, abs).replace(/\\/g, '/');
    }
}

export const registry = PathRegistry.getInstance();

import * as fs from 'fs';
import * as path from 'path';
import { registry } from './pathRegistry.js';

/**
 * Operation PennyOne: Configuration-Driven Persona Registry
 * Purpose: Centralize persona lore, prefixes, and identity to eliminate hardcoded strings.
 */
export interface ActivePersona {
    name: string;
    prefix: string;
    loreFile: string;
}

export class PersonaRegistry {
    private static instance: PersonaRegistry;
    private persona: ActivePersona;

    private constructor() {
        this.persona = this.loadConfig();
    }

    public static getInstance(): PersonaRegistry {
        if (!PersonaRegistry.instance) {
            PersonaRegistry.instance = new PersonaRegistry();
        }
        return PersonaRegistry.instance;
    }

    /**
     * Loads the active persona from the system configuration.
     * @returns The active persona configuration.
     */
    private loadConfig(): ActivePersona {
        try {
            const root = registry.getRoot();
            const configPath = path.join(root, '.agent', 'config.json');
            if (fs.existsSync(configPath)) {
                const configData = fs.readFileSync(configPath, 'utf-8');
                const data = JSON.parse(configData);
                // Support legacy and active structures
                const personaStr = data.system?.persona || data.persona || data.Persona || 'ALFRED';
                return this.hydratePersona(personaStr);
            }
        } catch (error: unknown) {
            const message = error instanceof Error ? error.message : String(error);
            console.warn(`[WARNING] Failed to load persona config: ${message}`);
        }
        return this.hydratePersona('ALFRED');
    }

    private hydratePersona(name: string): ActivePersona {
        const upper = name.toUpperCase();
        if (upper === 'O.D.I.N.' || upper === 'ODIN') {
            return {
                name: 'O.D.I.N.',
                prefix: '[O.D.I.N.]',
                loreFile: 'odin.qmd'
            };
        }

        // Default to ALFRED
        return {
            name: 'A.L.F.R.E.D.',
            prefix: '[A.L.F.R.E.D.]',
            loreFile: 'alfred.qmd'
        };
    }

    public getPersona(): ActivePersona {
        return this.persona;
    }
}

export const activePersona = PersonaRegistry.getInstance().getPersona();
